SELECT CAST(COUNT(CASE WHEN T1.height < 180 AND T2.overall_rating > 70 THEN 1 ELSE NULL END) AS REAL) * 100 / COUNT(T1.id) AS percentage
FROM Player AS T1
JOIN Player_Attributes AS T2 ON T1.player_api_id = T2.player_api_id;

352:
SELECT CAST(COUNT(CASE WHEN T2.language = 'Chinese Simplified' THEN T1.id ELSE NULL END) AS REAL) * 100 / COUNT(T1.id) AS percentage_chinese_simplified
FROM cards AS T1
JOIN foreign_data AS T2 ON T1.uuid = T2.uuid;

